from tkinter import *root=Tk()def somme():    a=t1.get()    b=t2.get()    s=int(a)+int(b)    t3.set(s)def add():    a = t1.get()    b = t2.get()    s = int(a) - int(b)    t3.set(s)def l9isma():    a = t1.get()    b = t2.get()    s = int(a) / int(b)    t3.set(s)def mul():    a = t1.get()    b = t2.get()    s = int(a) * int(b)    t3.set(s)t1=StringVar()t2=StringVar()t3=StringVar()root.geometry("600x600")root.title("calucatris")root.iconbitmap("20àç.ico")myStyle="{arial} 21 bold"root.resizable(True , True)l=Label(root,font=myStyle,bg="black",fg="white").place(x=0,y=0,width=600,height=600)l1=Label(root,font=myStyle,text="taper nomber").place(x=22,y=12)l2=Entry(root,font=myStyle,textvariable=t1,bg="orange",fg="white",border="0").place(x=222,y=12,width=141,height=38)l3=Label(root,font=myStyle,text="taper nomber").place(x=22,y=73)l4=Entry(root,font=myStyle,textvariable=t2,bg="orange",fg="white",border="0").place(x=222,y=73,width=141,height=38)b=Button(root,font=myStyle,bg="red",fg="black",text=" + ",command=somme,border="0").place(x=60,y=160,width=61,height=38)b1=Button(root,font=myStyle,bg="red",fg="black",text=" - ",command=add,border="0").place(x=260,y=160,width=61,height=38)b2=Button(root,font=myStyle,bg="red",fg="black",text=" / ",command=l9isma,border="0").place(x=60,y=240,width=61,height=38)b3=Button(root,font=myStyle,bg="red",fg="black",text=" * ",command=mul,border="0").place(x=260,y=240,width=61,height=38)l5=Label(root,font=myStyle,text="RESULTA").place(x=30,y=350)l6=Entry(root,font=myStyle,textvariable=t3,bg="blue",fg="white",border="0").place(x=230,y=350,width=141,height=38)root.mainloop()